mapper.select:
SELECT * FROM cd_code_group

    (tenant_id IS NULL
    OR tenant_id = #{tenantId}
    )

ORDER BY tenant_id NULLS FIRST, group_code ASC

SELECT * FROM cd_code_group
WHERE group_code = #{groupCode}
  AND (tenant_id IS NULL
        OR tenant_id = #{tenantId}
      )
ORDER BY tenant_id NULLS LAST
LIMIT 1

SELECT
    c.id, c.tenant_id, c.group_id, g.group_code,
    c.code, c.name, c.description, c.parent_id, c.sort_order, c.active,
    c.attributes_json, c.created_at, c.updated_at, c.version
FROM cd_code c
JOIN cd_code_group g ON g.id = c.group_id
WHERE g.group_code = #{groupCode}
  AND c.code = #{code}
  AND (c.tenant_id IS NULL
        OR c.tenant_id = #{tenantId}
      )
ORDER BY c.tenant_id NULLS LAST
LIMIT 1

mapper.insert:
