#{i.attributesJson, typeHandler=com.tulip.common.data.handler.JsonbTypeHandler}
'{}'::jsonb , now(), now(), 0 )

mapper.select:
SELECT COUNT(*) FROM cd_code
WHERE group_id = #{groupId}
  AND code = #{code}
  AND id <> #{excludeId}
